import { useNavigate } from 'react-router-dom';
import { FrstImageInfo, FrstInfoImage } from '../components/ImageInfo';


function AboutUs() {
    const navigate = useNavigate();
    const handleRouting = (route, pageName) => {
        navigate(route, { state: pageName ? { pageName: pageName, imageSrc: "beautiful-beach-using-young-happy.jpg" } : null });
    };
    return (
        <>
            <section >
                <div className='container pt-5'>
                    <div className='row'>
                        <div className='col-md-6 my-5 text-end pe-5'>
                            <h1>About Our</h1>
                            <h5>Why choose us?</h5>
                        </div>
                        <div className='col-md-6 my-5'>
                            <p>Our agency is built on the vision of discovering, guiding, and developing talented individuals who aspire to grow in the fashion and creative industry. We work closely with models, brands, photographers, and designers to create opportunities that bring creativity and professionalism together. Through portfolio development, brand collaborations, and fashion events, we aim to help models build strong careers while supporting brands in finding the right talent for their projects.
                                < br />< br />
                                With a focus on trust, quality, and long-term relationships, our team is committed to shaping a space where talent and opportunity meet to create meaningful work in the world of fashion.</p>
                        </div>
                    </div>
                </div>
            </section >
            <section>
                <div className='container-fluid pb-5 p-0'>
                    <FrstImageInfo handleRouting={handleRouting} />
                    <FrstInfoImage handleRouting={handleRouting} />
                </div>
            </section>
        </>
    )
}

export default AboutUs;